final:
module RefModule (
    input wire clk,
    input wire write_enable,
    input wire data_in,
    output reg data_out
);
    reg obf_stored_data;

    always @(posedge clk) begin
        if (write_enable) begin
            obf_stored_data <= data_in;
        end
    end

    always @(posedge clk) begin
        data_out <= obf_stored_data;
    end
endmodule
